18	//
19	// Cygwin runs Windows-native binaries from a POSIX-style shell. Paths cross
20	// the boundary in both directions:
21	//
22	//   - Intake (POSIX → native): env vars and arguments arrive as
23	//     `/cygdrive/c/...` or bare `/home/...` from Cygwin bash; Rust's PathBuf
24	//     joins them with backslashes on a Windows target, producing mixed
25	//     `/cygdrive/c/...\rbtd` paths Windows resolves unpredictably.
26	//   - Outflow (native → POSIX): PathBuf::display() emits native form
27	//     (`C:\foo\bar`); embedded in a bash script or env var consumed by
28	//     Cygwin bash, the consumer sees an unparseable path.
29	//
30	// This module provides the two conversions plus a cached Cygwin-detection
31	// probe. On Linux and macOS both conversions are identity, so call sites
32	// can be unconditional.
33	
34	use std::path::{Path, PathBuf};
35	use std::process::Command;
36	use std::sync::OnceLock;
37	
38	static RBTDRX_IS_CYGWIN: OnceLock<bool> = OnceLock::new();
39	
40	/// Detect whether we're running under a Cygwin-spawned shell environment.
41	///
42	/// On Cygwin, the launching bash exports `OSTYPE=cygwin` to spawned
43	/// processes — including Windows-native binaries like a
44	/// `x86_64-pc-windows-gnu` theurge. Result is cached for binary lifetime.
45	pub fn rbtdrx_is_cygwin() -> bool {
46	    *RBTDRX_IS_CYGWIN.get_or_init(|| {
47	        matches!(std::env::var("OSTYPE").as_deref(), Ok("cygwin"))
48	    })
49	}
50	
51	/// Convert a path string from POSIX form (as Cygwin bash uses) to native
52	/// PathBuf form (as the Windows OS uses). On non-Cygwin platforms, identity.
53	///
54	/// Returns `Err` only when running on Cygwin AND the path is not a recognised
55	/// fast-path shape AND the `cygpath` fallback fails — i.e., the platform
56	/// claims Cygwin via OSTYPE but cygpath is unreachable.
57	pub fn rbtdrx_posix_to_native(s: &str) -> Result<PathBuf, String> {
58	    rbtdrx_posix_to_native_for(s, rbtdrx_is_cygwin())
59	}
60	
61	/// Convert a Path from native form to POSIX form suitable for embedding in
62	/// a Cygwin bash script or for passing as an env var to a Cygwin-bash
63	/// tabtarget. On non-Cygwin platforms, returns the path's display form.
64	///
65	/// Best-effort: on Cygwin, falls back to `cygpath -u` for unrecognised
66	/// native shapes; if cygpath fails the original display form is returned
67	/// rather than failing the caller. Outflow sites (env vars, format!
68	/// interpolations) cannot meaningfully propagate errors mid-script.
69	pub fn rbtdrx_native_to_posix(p: &Path) -> String {
70	    rbtdrx_native_to_posix_for(&p.to_string_lossy(), rbtdrx_is_cygwin())
71	}
