73	// ── Pure implementation — explicit is_cygwin parameter for unit tests ──
74	
75	pub(crate) fn rbtdrx_posix_to_native_for(s: &str, is_cygwin: bool) -> Result<PathBuf, String> {
76	    if !is_cygwin {
77	        return Ok(PathBuf::from(s));
78	    }
79	
80	    // Fast path: /cygdrive/X/foo → X:\foo
81	    if let Some(native) = rbtdrx_cygdrive_to_native(s) {
82	        return Ok(native);
83	    }
84	
85	    // Already native Windows form (drive-letter prefix)
86	    if rbtdrx_looks_native_windows(s) {
87	        return Ok(PathBuf::from(s));
88	    }
89	
90	    // Slow path: bare POSIX (/home/..., /tmp/...) needs cygpath
91	    rbtdrx_cygpath(s, "-w")
92	        .map(PathBuf::from)
93	        .ok_or_else(|| format!("rbtdrx: cygpath -w failed for '{}'", s))
94	}
95	
96	pub(crate) fn rbtdrx_native_to_posix_for(s: &str, is_cygwin: bool) -> String {
97	    if !is_cygwin {
98	        return s.to_string();
99	    }
100	
101	    // Fast path: X:\foo or X:/foo → /cygdrive/x/foo
102	    if let Some(posix) = rbtdrx_drive_to_cygdrive(s) {
103	        return posix;
104	    }
105	
106	    // Already POSIX-looking: normalise any backslashes, return
107	    if s.starts_with('/') {
108	        return s.replace('\\', "/");
109	    }
110	
111	    // Slow path: cygpath -u; fall back to the original form
112	    rbtdrx_cygpath(s, "-u").unwrap_or_else(|| s.to_string())
113	}
114	
115	// ── Fast-path conversions (pure, unit-testable) ────────────────────────
116	
117	/// Match `/cygdrive/X[/tail]` and produce `X:\tail`. Returns None if the
118	/// input does not match this shape.
119	pub(crate) fn rbtdrx_cygdrive_to_native(s: &str) -> Option<PathBuf> {
120	    let rest = s.strip_prefix("/cygdrive/")?;
121	    let mut chars = rest.chars();
122	    let drive = chars.next()?;
123	    if !drive.is_ascii_alphabetic() {
124	        return None;
125	    }
126	    let tail = chars.as_str();
127	    // Drive must be followed by '/' or end-of-string — otherwise it's not
128	    // /cygdrive/X form but something like /cygdrive/foo.
129	    if !tail.is_empty() && !tail.starts_with('/') {
130	        return None;
131	    }
132	    let drive_upper = drive.to_ascii_uppercase();
133	    let win_tail = tail.replace('/', "\\");
134	    Some(PathBuf::from(format!("{}:{}", drive_upper, win_tail)))
135	}
136	
137	/// Match a drive-letter native path (`X:\foo`, `X:/foo`, or bare `X:`) and
138	/// produce the corresponding `/cygdrive/x/foo` form.
139	pub(crate) fn rbtdrx_drive_to_cygdrive(s: &str) -> Option<String> {
140	    let bytes = s.as_bytes();
141	    if bytes.len() < 2 {
142	        return None;
143	    }
144	    if !bytes[0].is_ascii_alphabetic() || bytes[1] != b':' {
145	        return None;
146	    }
147	    let drive = (bytes[0] as char).to_ascii_lowercase();
148	    let tail = &s[2..];
149	    if tail.is_empty() {
150	        return Some(format!("/cygdrive/{}", drive));
151	    }
152	    let posix_tail = tail.replace('\\', "/");
153	    let posix_tail = if posix_tail.starts_with('/') {
154	        posix_tail
155	    } else {
156	        format!("/{}", posix_tail)
157	    };
158	    Some(format!("/cygdrive/{}{}", drive, posix_tail))
